exercises.solution_code:
#include <iostream>

void applyIncrements(int x)
{
    std::cout << ++x << '\n'; // 1. prefix increment: x becomes x+1, print new value
    std::cout << x++ << '\n'; // 2. postfix increment: print current value, then x becomes x+1
    std::cout << x   << '\n'; // 3. current value after postfix increment
    std::cout << --x << '\n'; // 4. prefix decrement: x becomes x-1, print new value
    std::cout << x-- << '\n'; // 5. postfix decrement: print current value, then x becomes x-1
}

int main()
{
    int x;
    std::cin >> x;
    applyIncrements(x);
    return 0;
}

