exercises.solution_code:
#include <iostream>

int main()
{
    int v1, v2, v3;
    std::cin >> v1 >> v2 >> v3;

    long long product = 1;
    int counter = 0;

    product *= v1;
    ++counter;
    std::cout << "After step " << counter << ": product = " << product << '\n';

    product *= v2;
    ++counter;
    std::cout << "After step " << counter << ": product = " << product << '\n';

    product *= v3;
    ++counter;
    std::cout << "After step " << counter << ": product = " << product << '\n';

    return 0;
}
